import { completeMurajaahAction } from "@/app/actions";
import { EmptyState, MessageBanner, PageHeading, SectionCard, StatusBadge } from "@/components/shared";
import { canInputSubmission, requireUser } from "@/lib/auth";
import { getMurajaahData } from "@/lib/data";
import { formatTanggal, tanggalHariIni } from "@/lib/utils";
import { AlarmClock, Check, CircleAlert, RefreshCw } from "lucide-react";
import { redirect } from "next/navigation";

export default async function MurajaahPage({ searchParams }: { searchParams: Promise<{ pesan?: string; galat?: string }> }) {
  const user = await requireUser();
  if (!canInputSubmission(user.role)) redirect("/dashboard?galat=Halaman%20muraja%27ah%20khusus%20ustadz%20dan%20admin.");
  const [data, params] = await Promise.all([getMurajaahData(user), searchParams]);
  const today = tanggalHariIni();
  const dueRows = data.rows.filter((item) => item.status === "terjadwal" && item.dueDate <= today);
  const upcomingRows = data.rows.filter((item) => item.status === "terjadwal" && item.dueDate > today);
  const completedRows = data.rows.filter((item) => item.status === "selesai");
  return <><PageHeading eyebrow="Penguatan Hafalan" title="Muraja'ah Terjadwal" description="Sistem menyusun pengulangan otomatis pada H+1, H+3, H+7, dan H+30 dari setiap setoran. Selesaikan bersama santri untuk menjaga hafalan." action={<span className="inline-flex items-center gap-2 rounded-xl border border-amber-100 bg-amber-50 px-3 py-2 text-xs font-bold text-amber-800"><AlarmClock size={16}/>{dueRows.length} perlu tindak lanjut</span>}/><MessageBanner message={params.galat} type="error"/><MessageBanner message={params.pesan}/><div className="grid gap-4 sm:grid-cols-3"><div className="rounded-2xl border border-amber-100 bg-amber-50 p-5"><p className="text-xs font-bold uppercase tracking-wider text-amber-700">Hari ini / terlewat</p><p className="mt-2 font-display text-3xl font-bold text-amber-900">{dueRows.length}</p></div><div className="rounded-2xl border border-sky-100 bg-sky-50 p-5"><p className="text-xs font-bold uppercase tracking-wider text-sky-700">Akan datang</p><p className="mt-2 font-display text-3xl font-bold text-sky-900">{upcomingRows.length}</p></div><div className="rounded-2xl border border-emerald-100 bg-emerald-50 p-5"><p className="text-xs font-bold uppercase tracking-wider text-emerald-700">Sudah selesai</p><p className="mt-2 font-display text-3xl font-bold text-emerald-900">{completedRows.length}</p></div></div><div className="mt-5 grid gap-5 xl:grid-cols-[1.3fr_.7fr]"><SectionCard title="Perlu ditindaklanjuti" subtitle="Prioritaskan yang sudah melewati jadwal"><div className="divide-y divide-slate-100">{dueRows.length ? dueRows.map((item) => <article key={item.id} className="flex flex-col gap-3 px-5 py-4 sm:flex-row sm:items-center"><span className={`grid size-10 shrink-0 place-items-center rounded-xl ${item.dueDate < today ? "bg-rose-50 text-rose-600" : "bg-amber-50 text-amber-600"}`}><RefreshCw size={19}/></span><div className="min-w-0 flex-1"><div className="flex flex-wrap items-center gap-2"><h3 className="text-sm font-bold text-slate-800">{item.studentName}</h3>{item.dueDate < today && <span className="inline-flex items-center gap-1 text-[10px] font-bold text-rose-600"><CircleAlert size={12}/>Terlewat</span>}</div><p className="mt-0.5 text-xs text-slate-500">{item.surah ?? "Setoran terdahulu"}{item.verseStart ? ` · ayat ${item.verseStart}–${item.verseEnd}` : ""} · Interval H+{item.intervalDays}</p></div><form action={completeMurajaahAction} className="flex gap-2"><input type="hidden" name="id" value={item.id}/><input name="resultNote" className="w-36 rounded-lg border border-slate-200 px-2.5 py-2 text-xs outline-none focus:border-emerald-500" placeholder="Catatan hasil"/><button className="inline-flex items-center gap-1 rounded-lg bg-emerald-700 px-3 py-2 text-xs font-bold text-white hover:bg-emerald-800"><Check size={15}/>Selesai</button></form></article>) : <EmptyState title="Alhamdulillah, tidak ada tugas" description="Tidak ada jadwal muraja'ah hari ini atau yang terlewat."/>}</div></SectionCard><SectionCard title="Agenda mendatang" subtitle="Persiapan pengulangan berikutnya"><div className="divide-y divide-slate-100">{upcomingRows.slice(0, 7).length ? upcomingRows.slice(0, 7).map((item) => <div key={item.id} className="flex items-center gap-3 px-5 py-3.5"><span className="grid size-9 place-items-center rounded-xl bg-sky-50 text-sky-600"><AlarmClock size={17}/></span><div className="min-w-0 flex-1"><p className="truncate text-sm font-bold text-slate-700">{item.studentName}</p><p className="truncate text-xs text-slate-500">{item.surah ?? "Hafalan terdahulu"}</p></div><p className="text-right text-[11px] font-bold text-sky-700">{formatTanggal(item.dueDate)}</p></div>) : <EmptyState title="Belum ada agenda" description="Agenda baru muncul otomatis setelah setoran dicatat."/>}</div></SectionCard></div>{completedRows.length > 0 && <SectionCard className="mt-5" title="Riwayat muraja'ah selesai" subtitle="Tindak lanjut yang sudah dicatat"><div className="divide-y divide-slate-100">{completedRows.slice(0, 5).map((item) => <div className="flex items-center justify-between gap-3 px-5 py-3" key={item.id}><div><p className="text-sm font-bold text-slate-700">{item.studentName} · {item.surah ?? "Hafalan"}</p><p className="mt-0.5 text-xs text-slate-500">{item.resultNote ?? "Selesai tanpa catatan"}</p></div><StatusBadge value="selesai"/></div>)}</div></SectionCard>}</>;
}
